SELECT "I_PRODUCT_NAME"
FROM "tpcds"."ITEM"
WHERE "I_MANUFACT_ID" >= 811 AND "I_MANUFACT_ID" <= 811 + 40 AND (((SELECT COUNT(*) AS "$f0"
FROM "tpcds"."ITEM"
WHERE "I_MANUFACT" = "ITEM"."I_MANUFACT" AND ("I_CATEGORY" = 'Women' AND CAST("I_COLOR" AS VARCHAR(20)) IN ('[COLOR.1]', '[COLOR.2]') AND CAST("I_UNITS" AS VARCHAR(10)) IN ('[UNIT.1]', '[UNIT.2]') AND CAST("I_SIZE" AS VARCHAR(20)) IN ('[SIZE.1]', '[SIZE.2]') OR "I_CATEGORY" = 'Women' AND CAST("I_COLOR" AS VARCHAR(20)) IN ('[COLOR.3]', '[COLOR.4]') AND CAST("I_UNITS" AS VARCHAR(10)) IN ('[UNIT.3]', '[UNIT.4]') AND CAST("I_SIZE" AS VARCHAR(20)) IN ('[SIZE.3]', '[SIZE.4]') OR "I_CATEGORY" = 'Men' AND CAST("I_COLOR" AS VARCHAR(20)) IN ('[COLOR.5]', '[COLOR.6]') AND CAST("I_UNITS" AS VARCHAR(10)) IN ('[UNIT.5]', '[UNIT.6]') AND CAST("I_SIZE" AS VARCHAR(20)) IN ('[SIZE.5]', '[SIZE.6]') OR "I_CATEGORY" = 'Men' AND CAST("I_COLOR" AS VARCHAR(20)) IN ('[COLOR.7]', '[COLOR.8]') AND CAST("I_UNITS" AS VARCHAR(10)) IN ('[UNIT.7]', '[UNIT.8]') AND CAST("I_SIZE" AS VARCHAR(20)) IN ('[SIZE.1]', '[SIZE.2]')) OR "I_MANUFACT" = "ITEM"."I_MANUFACT" AND ("I_CATEGORY" = 'Women' AND CAST("I_COLOR" AS VARCHAR(20)) IN ('[COLOR.10]', '[COLOR.9]') AND CAST("I_UNITS" AS VARCHAR(10)) IN ('[UNIT.10]', '[UNIT.9]') AND CAST("I_SIZE" AS VARCHAR(20)) IN ('[SIZE.1]', '[SIZE.2]') OR "I_CATEGORY" = 'Women' AND CAST("I_COLOR" AS VARCHAR(20)) IN ('[COLOR.11]', '[COLOR.12]') AND CAST("I_UNITS" AS VARCHAR(10)) IN ('[UNIT.11]', '[UNIT.12]') AND CAST("I_SIZE" AS VARCHAR(20)) IN ('[SIZE.3]', '[SIZE.4]') OR "I_CATEGORY" = 'Men' AND CAST("I_COLOR" AS VARCHAR(20)) IN ('[COLOR.13]', '[COLOR.14]') AND CAST("I_UNITS" AS VARCHAR(10)) IN ('[UNIT.13]', '[UNIT.14]') AND CAST("I_SIZE" AS VARCHAR(20)) IN ('[SIZE.5]', '[SIZE.6]') OR "I_CATEGORY" = 'Men' AND CAST("I_COLOR" AS VARCHAR(20)) IN ('[COLOR.15]', '[COLOR.16]') AND CAST("I_UNITS" AS VARCHAR(10)) IN ('[UNIT.15]', '[UNIT.16]') AND CAST("I_SIZE" AS VARCHAR(20)) IN ('[SIZE.1]', '[SIZE.2]'))))) > 0
GROUP BY "I_PRODUCT_NAME"
ORDER BY "I_PRODUCT_NAME"
FETCH NEXT 100 ROWS ONLY
